mapper.select:
SELECT
FROM song s INNER JOIN song_artist sa ON s.song_id = sa.song_id AND sa.role_type = 0 INNER JOIN artist art ON sa.artist_id = art.artist_id INNER JOIN album a ON s.album_id = a.album_id WHERE s.status = 0 AND s.song_id IN
#{songId}

mapper.update:
update song
set play_count = play_count + #{inc}
WHERE song_id = #{songId}
